/**
 * DataverseDataSource — IDataSource implementation backed by Microsoft Dataverse.
 *
 * On initialize() it fetches all vehicle records from the vpi_vehicledatas
 * table via the Power Pages portal Web API (with @odata.nextLink pagination).
 * Once loaded, all lookups, filters, analytics, and valuations run in-memory
 * using the same computation engine as the ExcelDataSource.
 *
 * This class is swapped in at the DataSourceProvider level — no UI components,
 * hooks, or repositories change (see MIGRATION.md).
 */

import type {
  IDataSource,
  Vehicle,
  VehiclePricing,
  VehicleHierarchy,
  VehicleFilters,
  VehicleSortOption,
  ValuationResult,
  ComparableVehicle,
  AnalyticsData,
  DashboardAnalytics,
  DashboardFilters,
  Inquiry,
} from '@types';

import { fetchVehicleCatalog } from '@webapi';
import { memoize } from '@utils';

import {
  buildVehicleHierarchy,
  applyVehicleFilters,
  sortVehicles,
  getComparableVehicles,
  computeValuation,
  computePriceRange,
  computeAnalytics,
  computeDashboardAnalytics,
  createDefaultPricing,
} from './vehicleComputations';

export class DataverseDataSource implements IDataSource {
  private initialized = false;
  private vehicles: Vehicle[] = [];
  private vehiclesById = new Map<string, Vehicle>();
  private pricingById = new Map<string, VehiclePricing>();
  private rawMinPrices = new Map<string, number>();
  private rawMaxPrices = new Map<string, number>();
  private hierarchy!: VehicleHierarchy;
  private inquiries: Inquiry[] = [];

  private memoizedAnalytics = memoize(() =>
    computeAnalytics(this.vehicles, this.pricingById),
  );
  private memoizedHierarchy = memoize(() =>
    buildVehicleHierarchy(this.vehicles),
  );
  private dashboardCache: DashboardAnalytics | null = null;

  /* ─── Lifecycle ──────────────────────────────────────── */

  async initialize(): Promise<void> {
    try {
      console.log('[DataverseDataSource] Fetching vehicle catalog from Dataverse...');
      const { vehicles: vehicleMap, pricings } = await fetchVehicleCatalog();

      this.vehiclesById = vehicleMap;
      this.pricingById = pricings;
      this.vehicles = [...vehicleMap.values()];

      console.log(
        `[DataverseDataSource] Loaded ${this.vehicles.length} vehicles, ${this.pricingById.size} pricing records`,
      );

      // Build raw min/max price maps (from pricing data)
      for (const [id, p] of this.pricingById) {
        if (p.minimumPrice > 0) this.rawMinPrices.set(id, p.minimumPrice);
        if (p.maximumPrice > 0) this.rawMaxPrices.set(id, p.maximumPrice);
      }

      this.hierarchy = this.memoizedHierarchy();
      this.initialized = true;
      console.log('[DataverseDataSource] Initialization complete.');
    } catch (err) {
      const message =
        err instanceof Error ? err.message : 'Failed to initialize Dataverse data source';
      console.error('[DataverseDataSource] Initialization failed:', message);
      throw new Error(message);
    }
  }

  isInitialized(): boolean {
    return this.initialized;
  }

  /* ─── Vehicles ───────────────────────────────────────── */

  async getVehicles(
    filters?: VehicleFilters,
    sort?: VehicleSortOption,
    page = 1,
    pageSize = 20,
  ): Promise<{ vehicles: Vehicle[]; total: number }> {
    let filtered = filters
      ? applyVehicleFilters(this.vehicles, this.pricingById, filters)
      : [...this.vehicles];

    if (sort) {
      filtered.sort((a, b) => sortVehicles(a, b, this.pricingById, sort));
    }

    const total = filtered.length;
    const start = (page - 1) * pageSize;
    const vehicles = filtered.slice(start, start + pageSize);

    return { vehicles, total };
  }

  async getVehicleById(id: string): Promise<Vehicle | null> {
    return this.vehiclesById.get(id) ?? null;
  }

  async getVehicleHierarchy(): Promise<VehicleHierarchy> {
    return this.memoizedHierarchy();
  }

  async getVehicleSpecs(year: number, make: string, model: string): Promise<Vehicle[]> {
    return this.vehicles.filter(
      (v) =>
        v.year === year &&
        v.make.toLowerCase() === make.toLowerCase() &&
        v.model.toLowerCase() === model.toLowerCase(),
    );
  }

  async searchVehicles(query: string, limit = 20): Promise<Vehicle[]> {
    const lower = query.toLowerCase();
    return this.vehicles
      .filter(
        (v) =>
          v.make.toLowerCase().includes(lower) ||
          v.model.toLowerCase().includes(lower) ||
          v.spec.toLowerCase().includes(lower) ||
          `${v.year} ${v.make} ${v.model}`.toLowerCase().includes(lower),
      )
      .slice(0, limit);
  }

  /* ─── Pricing ────────────────────────────────────────── */

  async getPricing(vehicleId: string): Promise<VehiclePricing | null> {
    return this.pricingById.get(vehicleId) ?? null;
  }

  async getPricingByCriteria(
    year: number,
    make: string,
    model: string,
    spec: string,
  ): Promise<VehiclePricing | null> {
    const vehicle = this.vehicles.find(
      (v) =>
        v.year === year &&
        v.make.toLowerCase() === make.toLowerCase() &&
        v.model.toLowerCase() === model.toLowerCase() &&
        v.spec.toLowerCase() === spec.toLowerCase(),
    );
    if (!vehicle) return null;
    return this.pricingById.get(vehicle.id) ?? null;
  }

  async getComparableVehicles(
    vehicleId: string,
    limit = 5,
  ): Promise<ComparableVehicle[]> {
    return getComparableVehicles(
      vehicleId,
      this.vehicles,
      this.pricingById,
      limit,
    );
  }

  async getValuation(
    year: number,
    make: string,
    model: string,
    spec: string,
    bodyType?: string,
  ): Promise<ValuationResult | null> {
    return computeValuation(
      this.vehicles,
      this.pricingById,
      this.rawMinPrices,
      this.rawMaxPrices,
      year,
      make,
      model,
      spec,
      bodyType,
    );
  }

  async getPriceRange(
    filters?: VehicleFilters,
  ): Promise<{ min: number; max: number; average: number }> {
    return computePriceRange(this.vehicles, this.pricingById, filters);
  }

  /* ─── Lookups ────────────────────────────────────────── */

  async getYears(): Promise<number[]> {
    return this.hierarchy.years;
  }

  async getMakes(year: number): Promise<string[]> {
    return this.hierarchy.makes[year] ?? [];
  }

  async getModels(year: number, make: string): Promise<string[]> {
    const key = `${year}-${make.toLowerCase()}`;
    return this.hierarchy.models[key] ?? [];
  }

  async getSpecs(year: number, make: string, model: string): Promise<string[]> {
    const key = `${year}-${make.toLowerCase()}-${model.toLowerCase()}`;
    return this.hierarchy.specs[key] ?? [];
  }

  /* ─── Analytics ──────────────────────────────────────── */

  async getAnalytics(): Promise<AnalyticsData> {
    return this.memoizedAnalytics();
  }

  async getAllVehiclesWithPricing(
    filters?: VehicleFilters,
  ): Promise<{ vehicle: Vehicle; pricing: VehiclePricing }[]> {
    const filtered = filters
      ? applyVehicleFilters(this.vehicles, this.pricingById, filters)
      : this.vehicles;
    return filtered
      .map((vehicle) => ({
        vehicle,
        pricing:
          this.pricingById.get(vehicle.id) ??
          createDefaultPricing(vehicle.id),
      }))
      .filter((vp) => vp.pricing.averagePrice > 0);
  }

  async getDashboardAnalytics(
    filters?: DashboardFilters,
  ): Promise<DashboardAnalytics> {
    // Return cached unfiltered result when possible
    if (!filters && this.dashboardCache) {
      return this.dashboardCache;
    }

    const result = computeDashboardAnalytics(
      this.vehicles,
      this.pricingById,
      filters,
    );

    if (!filters) {
      this.dashboardCache = result;
    }

    return result;
  }

  /* ─── Inquiries ──────────────────────────────────────── */

  async saveInquiry(inquiry: Inquiry): Promise<void> {
    this.inquiries.push(inquiry);
    // TODO: Persist to Dataverse vpi_contact / vpi_inquiry tables
    //   await dataverseAjax({ type: 'POST', url: '/_api/vpi_inquiries', data: JSON.stringify(payload) });
  }

  async getInquiries(): Promise<Inquiry[]> {
    return [...this.inquiries];
  }

  async getInquiryById(id: string): Promise<Inquiry | null> {
    return this.inquiries.find((i) => i.id === id) ?? null;
  }

  async updateInquiryStatus(id: string, status: Inquiry['status']): Promise<void> {
    const inquiry = this.inquiries.find((i) => i.id === id);
    if (inquiry) {
      inquiry.status = status;
    }
  }
}
