/* ─── Seats (vpi_seats) — numeric, stored as option set ── */
/* (Parsed from the formatted value at mapping time)        */
/* ─── Year (vpi_year) — stored as text, parsed to number ─ */

/**
 * Normalise a formatted option set value against the canonical labels.
 * Returns the matched canonical label, or the fallback if no match found.
 */
export function normaliseOptionSet(
  formattedValue: string | null | undefined,
  validLabels: readonly string[],
  fallback: string,
): string {
  if (!formattedValue) return fallback;
  const trimmed = formattedValue.trim();
  const match = validLabels.find(
    (v) => v.toLowerCase() === trimmed.toLowerCase(),
  );
  return match ?? fallback;
}
