/**
 * Dataverse Vehicle Data Fetcher
 *
 * Fetches all vehicle records from the vpi_vehicledatas table via the
 * Power Pages portal Web API. Handles OData pagination (@odata.nextLink)
 * with a do-while loop and maps raw columns to the application's Vehicle
 * and VehiclePricing types.
 *
 * @see https://learn.microsoft.com/en-us/power-pages/configure/web-api-odata
 */

import type { Vehicle, VehiclePricing } from '@types';
import type {
  DataverseVehicleRow,
  DataverseVehicleRecord,
  ODataResponse,
} from './dataverseTypes';
import { waitForSafeAjax } from './safeAjaxLoader';
import { normaliseOptionSet } from './optionSetMappings';
import {
  bodyTypeLabels,
  vehicleTypeLabels,
  fuelTypeLabels,
  categoryLabels,
  drivetrainLabels,
  transmissionLabels,
} from './optionSetMappings';

/* ─── Normalization helpers ───────────────────────────── */

/** Parse an integer safely */
function parseIntVal(
  value: number | string | null | undefined,
): number {
  if (value == null) return 0;
  if (typeof value === 'number') return Math.round(value);
  const parsed = parseInt(value, 10);
  return isNaN(parsed) ? 0 : parsed;
}

/** Parse a decimal value safely */
function parseDecimal(
  value: number | null | undefined,
): number {
  return value ?? 0;
}

function parseCurrency(
  value: number | null | undefined,
): number {
  return value ?? 0;
}

/* ─── Mapper ──────────────────────────────────────────── */

/**
 * Convert a raw Dataverse row to a Vehicle + VehiclePricing pair.
 */
function convertToVehicleRecord(
  row: DataverseVehicleRow,
): DataverseVehicleRecord {
  const id = row.vpi_vehicledataid;

  const vehicle: Vehicle = {
    id,
    year: parseIntVal(row.vpi_year),
    make: row.vpi_make?.trim() ?? '',
    model: row.vpi_model?.trim() ?? '',
    spec: row.vpi_spec?.trim() ?? '',
    trim: row.vpi_spec?.trim() ?? '',
    engineSize: parseDecimal(row.vpi_enginesize),
    horsepower: parseIntVal(row.vpi_horsepower),
    cylinders: parseIntVal(row.vpi_cylinders),
    doors: parseIntVal(
      row['vpi_doors@OData.Community.Display.V1.FormattedValue'],
    ),
    seats: parseIntVal(
      row['vpi_seats@OData.Community.Display.V1.FormattedValue'],
    ),
    transmission: normaliseOptionSet(
      row['vpi_transmissiontronic@OData.Community.Display.V1.FormattedValue'],
      transmissionLabels,
      'Automatic',
    ) as Vehicle['transmission'],
    bodyType: normaliseOptionSet(
      row['vpi_bodytype@OData.Community.Display.V1.FormattedValue'],
      bodyTypeLabels,
      'Suv',
    ) as Vehicle['bodyType'],
    driveType: normaliseOptionSet(
      row['vpi_drivetype@OData.Community.Display.V1.FormattedValue'],
      drivetrainLabels,
      'Unknown',
    ) as Vehicle['driveType'],
    vehicleType: normaliseOptionSet(
      row['vpi_vehicletype@OData.Community.Display.V1.FormattedValue'],
      vehicleTypeLabels,
      'Car',
    ) as Vehicle['vehicleType'],
    category: normaliseOptionSet(
      row['vpi_category@OData.Community.Display.V1.FormattedValue'],
      categoryLabels,
      'OTHER/STANDARD',
    ) as Vehicle['category'],
    powertrain: normaliseOptionSet(
      row['vpi_powertraintype@OData.Community.Display.V1.FormattedValue'],
      fuelTypeLabels,
      'Petrol/Diesel',
    ) as Vehicle['powertrain'],
    description: row.vpi_description?.trim() ?? '',
  };

  const avgPrice = parseCurrency(row.vpi_avgprice);
  const minPrice = parseCurrency(row.vpi_minprice);
  const maxPrice = parseCurrency(row.vpi_maxprice);

  const pricing: VehiclePricing = {
    vehicleId: id,
    averagePrice: avgPrice,
    minimumPrice: minPrice,
    maximumPrice: maxPrice,
    medianPrice: avgPrice,
    standardDeviation: 0,
    sampleSize: 1,
    priceRange: {
      min: minPrice,
      max: maxPrice,
      average: avgPrice,
      median: avgPrice,
      p10: 0,
      p25: 0,
      p75: 0,
      p90: 0,
    },
    confidenceScore: 0,
    marketTrend: {
      direction: 'stable',
      percentage: 0,
      periodMonths: 3,
      volatility: 'low',
    },
    lastUpdated: new Date(),
  };

  return { vehicle, pricing };
}

/* ─── Paginated Fetcher ──────────────────────────────── */

const BASE_SELECT =
  '$select=vpi_vehicledataid,vpi_avgprice,vpi_bodytype,vpi_category,vpi_cylinders,vpi_description,vpi_doors,vpi_drivetype,vpi_enginesize,vpi_horsepower,vpi_id,vpi_make,vpi_makecode,vpi_maxprice,vpi_minprice,vpi_model,vpi_modelcode,vpi_name,vpi_powertraintype,vpi_pricespreadpct,vpi_seats,vpi_spec,vpi_transmissiontronic,vpi_vehicletype,vpi_year,vpi_yearcode';

const BASE_HEADERS: Record<string, string> = {
  'Content-Type': 'application/json',
  Prefer: 'odata.include-annotations=*',
};

/**
 * Fetch ALL vehicle records from the Dataverse vpi_vehicledatas table.
 *
 * Uses a do-while loop to follow @odata.nextLink pagination so that all
 * 33,000+ records are retrieved in full. Results are mapped to the
 * application's Vehicle + VehiclePricing types.
 *
 * @param baseUrl - The OData endpoint URL (default: /_api/vpi_vehicledatas)
 * @returns Array of mapped vehicle + pricing records
 */
export async function fetchAllVehicles(
  baseUrl = '/_api/vpi_vehicledatas',
): Promise<DataverseVehicleRecord[]> {
  // Wait for safeAjax (Power Pages globals jQuery + shell) to become available.
  // On portal pages the runtime typically initialises within 1-2 seconds,
  // but if the app bundle loaded early we poll up to 15s.
  if (!(await waitForSafeAjax())) {
    throw new Error(
      'safeAjax not available after 15s timeout. Ensure the app is running inside a Power Pages portal page where jQuery and shell globals are provided by the portal runtime.',
    );
  }

  const safeAjax = window.webapi!.safeAjax;

  const allRecords: DataverseVehicleRecord[] = [];
  let nextUrl: string | undefined = `${baseUrl}?${BASE_SELECT}`;
  let pageCount = 0;

  do {
    pageCount++;

    const response = await new Promise<ODataResponse<DataverseVehicleRow>>(
      (resolve, reject) => {
        safeAjax({
          type: 'GET',
          url: nextUrl,
          contentType: 'application/json',
          headers: { ...BASE_HEADERS },
          success: (data: ODataResponse<DataverseVehicleRow>) =>
            resolve(data),
          error: (
            xhr: { status: number },
            _textStatus: string,
            errorThrown: string,
          ) => {
            console.error(
              `[vehicleFetcher] Page ${pageCount} failed:`,
              xhr.status,
              errorThrown,
            );
            reject(
              new Error(
                `Dataverse API error (page ${pageCount}): ${xhr.status} ${errorThrown}`,
              ),
            );
          },
        });
      },
    );

    // Map this page's rows
    const pageRecords = (response.value ?? []).map(convertToVehicleRecord);
    allRecords.push(...pageRecords);

    console.log(
      `[vehicleFetcher] Page ${pageCount}: fetched ${pageRecords.length} records (total: ${allRecords.length})`,
    );

    // Follow the next link if present
    nextUrl = response['@odata.nextLink'];
  } while (nextUrl);

  console.log(
    `[vehicleFetcher] Complete — fetched ${allRecords.length} vehicles in ${pageCount} pages`,
  );

  return allRecords;
}

/**
 * Fetch vehicles and return only the mapped Vehicle[] (without pricing).
 */
export async function fetchVehiclesOnly(
  baseUrl?: string,
): Promise<Vehicle[]> {
  const records = await fetchAllVehicles(baseUrl);
  return records.map((r) => r.vehicle);
}

/**
 * Fetch vehicles and return separate collections of vehicles + pricings.
 */
export async function fetchVehicleCatalog(
  baseUrl?: string,
): Promise<{ vehicles: Map<string, Vehicle>; pricings: Map<string, VehiclePricing> }> {
  const records = await fetchAllVehicles(baseUrl);
  const vehicles = new Map<string, Vehicle>();
  const pricings = new Map<string, VehiclePricing>();

  for (const record of records) {
    vehicles.set(record.vehicle.id, record.vehicle);
    pricings.set(record.vehicle.id, record.pricing);
  }

  return { vehicles, pricings };
}
